import React, { Component } from "react";

class CurrencyConvertor extends Component {

    constructor(props) {
        super(props);

        this.state = {
            rupees: "",
            euro: ""
        };
    }

    handleRupeesChange = (event) => {
        this.setState({
            rupees: event.target.value
        });
    };

    handleSubmit = (event) => {

        event.preventDefault();

        const euro = (this.state.rupees / 90).toFixed(2);

        this.setState({
            euro: euro
        });
    };

    render() {

        return (

            <div style={{ marginTop: "30px" }}>

                <h2 style={{ color: "green" }}>
                    Currency Convertor!!!
                </h2>

                <form onSubmit={this.handleSubmit}>

                    <table>

                        <tbody>

                            <tr>

                                <td>Amount (₹):</td>

                                <td>

                                    <input
                                        type="number"
                                        value={this.state.rupees}
                                        onChange={this.handleRupeesChange}
                                        placeholder="Enter Amount"
                                    />

                                </td>

                            </tr>

                            <tr>

                                <td>:</td>

                                <td>

                                    <input
                                        type="text"
                                        value={this.state.euro}
                                        readOnly
                                    />

                                </td>

                            </tr>

                            <tr>

                                <td></td>

                                <td>

                                    <button type="submit">
                                        Submit
                                    </button>

                                </td>

                            </tr>

                        </tbody>

                    </table>

                </form>

            </div>

        );

    }

}

export default CurrencyConvertor;
